function CronRunner() {
  const [jobs, setJobs] = React.useState([]);
  const [name, setName] = React.useState('REPLACE_WITH_NAME');
  const [expr, setExpr] = React.useState('REPLACE_WITH_CRON');
  const [task, setTask] = React.useState('REPLACE_WITH_TASK');
  const [busy, setBusy] = React.useState(false);
  const refresh = async () => {
    try { const r = await titan.api.call('/api/cron', { method: 'GET' }); setJobs(Array.isArray(r)?r:(r?.jobs||[])); } catch {}
  };
  React.useEffect(() => { refresh(); const id = setInterval(refresh, 5000); return () => clearInterval(id); }, []);
  const create = async () => {
    if (!name || !expr || !task) return;
    setBusy(true);
    try { await titan.api.call('/api/cron', { method: 'POST', body: { name, schedule: expr, prompt: task } }); await refresh(); }
    catch (e) { alert('Create failed: ' + (e?.message||e)); }
    finally { setBusy(false); }
  };
  const remove = async (id) => {
    if (!confirm('Delete this cron job?')) return;
    try { await titan.api.call(`/api/cron/${id}`, { method: 'DELETE' }); await refresh(); } catch (e) { alert(e?.message||e); }
  };
  return (
    <div style={{padding:14,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:10}}>
      <div style={{fontSize:16,fontWeight:600}}>Scheduled Tasks</div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 2fr auto',gap:6}}>
        <input value={name} onChange={e=>setName(e.target.value)} placeholder="Name" style={{padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <input value={expr} onChange={e=>setExpr(e.target.value)} placeholder="Cron (e.g. 0 9 * * *)" style={{padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:13,fontFamily:'monospace'}}/>
        <input value={task} onChange={e=>setTask(e.target.value)} placeholder="What should TITAN do?" style={{padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <button onClick={create} disabled={busy} style={{padding:'6px 14px',borderRadius:6,border:'none',background:'#007AFF',color:'#fff',cursor:busy?'wait':'pointer',fontWeight:600}}>{busy?'…':'Add'}</button>
      </div>
      <div style={{flex:1,overflow:'auto',border:'1px solid #eee',borderRadius:8}}>
        {jobs.length === 0 ? <div style={{padding:20,textAlign:'center',color:'#888'}}>No scheduled tasks yet.</div> :
          jobs.map((j,i) => (
            <div key={j.id||i} style={{display:'grid',gridTemplateColumns:'2fr 1.5fr 3fr auto',gap:8,padding:'10px 12px',borderBottom:'1px solid #f0f0f0',alignItems:'center',fontSize:13}}>
              <div style={{fontWeight:600}}>{j.name||j.id}</div>
              <code style={{fontSize:12,color:'#555'}}>{j.schedule||j.expr}</code>
              <div style={{color:'#666',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{j.prompt||j.task}</div>
              <button onClick={()=>remove(j.id)} style={{padding:'4px 10px',border:'1px solid #ddd',background:'#fff',borderRadius:4,cursor:'pointer',fontSize:12}}>✕</button>
            </div>
          ))
        }
      </div>
      <div style={{fontSize:11,color:'#888'}}>Tip: <code>0 9 * * *</code> = 9 AM daily. <code>*/15 * * * *</code> = every 15 min.</div>
    </div>
  );
}
render(<CronRunner/>);
